import{_ as e,o as t,c as i,a2 as a}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Settings And Secrets","description":"","frontmatter":{},"headers":[],"relativePath":"admin/settings-secrets.md","filePath":"admin/settings-secrets.md","lastUpdated":null}'),n={name:"admin/settings-secrets.md"};function l(r,s,o,d,h,p){return t(),i("div",null,[...s[0]||(s[0]=[a(`<h1 id="settings-and-secrets" tabindex="-1">Settings And Secrets <a class="header-anchor" href="#settings-and-secrets" aria-label="Permalink to &quot;Settings And Secrets&quot;">​</a></h1><p>Autofac has an Admin-only Settings control plane at <code>/settings</code> and <code>/api/settings</code>. It centralizes the values operators need most often: model provider, integrations, authentication, runtime mode, storage, sandboxing, observability, and Settings storage.</p><h2 id="access-model" tabindex="-1">Access model <a class="header-anchor" href="#access-model" aria-label="Permalink to &quot;Access model&quot;">​</a></h2><ul><li>The Settings API is protected by the <code>Admin</code> policy.</li><li>Non-admin users should not fetch or mutate settings.</li><li>Every settings update and readiness check writes a redacted audit record.</li></ul><h2 id="configuration-precedence" tabindex="-1">Configuration precedence <a class="header-anchor" href="#configuration-precedence" aria-label="Permalink to &quot;Configuration precedence&quot;">​</a></h2><p>Autofac starts from normal .NET configuration:</p><ul><li><code>appsettings*.json</code></li><li>environment variables</li><li>user secrets</li><li>Helm values</li><li>Compose env files</li><li>deployment-provided secret sources</li></ul><p>The Settings layer adds two local files that are loaded after bootstrap configuration:</p><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>config/settings.overrides.json</code></td><td>Non-secret runtime overrides.</td></tr><tr><td><code>config/settings.secrets.json</code></td><td>Local secret rotations.</td></tr></tbody></table><p>Change the default paths:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Settings__OverridesPath</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/path/to/settings.overrides.json</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Settings__SecretsPath</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/path/to/settings.secrets.json</span></span></code></pre></div><p>Because Settings files load after appsettings and environment values, saved settings take precedence after API restart. The UI marks most saved changes as restart-required because services bind options at startup.</p><h2 id="secret-handling" tabindex="-1">Secret handling <a class="header-anchor" href="#secret-handling" aria-label="Permalink to &quot;Secret handling&quot;">​</a></h2><p>Secret fields are never returned as raw values by <code>/api/settings</code>. The API returns:</p><ul><li>configured or missing status</li><li>source</li><li>short fingerprint</li><li>whether local secret writes are enabled</li></ul><p>Secret rotation inputs are write-only in the UI. After save, the browser clears the input. Audit records include the changed path but not the value.</p><h2 id="production-secret-policy" tabindex="-1">Production secret policy <a class="header-anchor" href="#production-secret-policy" aria-label="Permalink to &quot;Production secret policy&quot;">​</a></h2><p>Local file-backed secret writes are useful for development and simple self-hosted installs. Production should prefer Kubernetes Secrets, cloud secret managers, environment injection, or a platform secret store.</p><p>Disable local secret writes:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Settings__AllowLocalSecretWrites</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">false</span></span></code></pre></div><p>Never commit:</p><ul><li>model API keys</li><li>GitHub personal access tokens</li><li>webhook secrets</li><li>JWT signing keys</li><li>database credentials</li><li>identity-provider client secrets</li></ul><h2 id="settings-groups" tabindex="-1">Settings groups <a class="header-anchor" href="#settings-groups" aria-label="Permalink to &quot;Settings groups&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Group</th><th>Examples</th></tr></thead><tbody><tr><td>Model</td><td>Provider, model, limits, retries, prompt caching, API key status.</td></tr><tr><td>Integrations</td><td>GitHub, Jira, Slack, Teams, webhook secrets, repository defaults.</td></tr><tr><td>Authentication</td><td>JWT issuer, audience, authority, dev auth controls, role mappings.</td></tr><tr><td>Runtime</td><td>Workflow runtime, policy file, optional Camunda settings.</td></tr><tr><td>Storage</td><td>Postgres status, filesystem/S3 artifact settings.</td></tr><tr><td>Sandbox</td><td>Docker, OpenSandbox, Kubernetes Kata provider controls.</td></tr><tr><td>Observability</td><td>Tracing settings and Settings storage paths.</td></tr></tbody></table><h2 id="readiness-checks" tabindex="-1">Readiness checks <a class="header-anchor" href="#readiness-checks" aria-label="Permalink to &quot;Readiness checks&quot;">​</a></h2><p>Settings can run dry-run readiness checks for:</p><ul><li>model provider</li><li>GitHub</li><li>Jira</li><li>Slack</li><li>Teams</li><li>Camunda</li></ul><p>These checks validate configuration completeness and audit the result. They should not send chat messages or mutate external systems.</p><h2 id="api-shape" tabindex="-1">API shape <a class="header-anchor" href="#api-shape" aria-label="Permalink to &quot;API shape&quot;">​</a></h2><p>Read the redacted catalog:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/api/settings&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ADMIN_TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span></span></code></pre></div><p>Patch supported values:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/api/settings&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PATCH</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ADMIN_TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;values&quot;: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Anthropic:Provider&quot;: &quot;mock&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Integrations:GitHub:Enabled&quot;: true</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    },</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;secrets&quot;: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Anthropic:ApiKey&quot;: &quot;new-value-sent-once&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    }</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span></span></code></pre></div><p>Secret paths sent under <code>values</code> are rejected. Non-secret paths sent under <code>secrets</code> are rejected. Unknown paths are rejected.</p>`,34)])])}const u=e(n,[["render",l]]);export{k as __pageData,u as default};
